page_settings.custom_css:
/* FUNAAB Green Palette */
:root {
  --green-primary: #006B3F;
  --green-bright: #00A859;
  --green-dark: #003D23;
  --green-deep: #005531;
  --green-tint: #E8F5EE;
  --green-muted: #B8D9C8;
  --gold: #D4A843;
  --gold-light: #F5E6B8;
  --ink: #1A2B23;
  --muted: #5E6E64;
  --light-muted: #8A9B90;
  --white: #FFFFFF;
  --off-white: #F7FAF8;
  --line: #D6E5DC;
  --line-light: #E8F0EB;
  --success: #00A859;
  --warning: #D4A843;
  --danger: #C0392B;
  --info: #2980B9;
  --shadow-sm: 0 2px 8px rgba(0,61,35,0.06);
  --shadow-md: 0 8px 24px rgba(0,61,35,0.1);
  --shadow-lg: 0 20px 50px rgba(0,61,35,0.15);
  --shadow-card: 0 4px 16px rgba(0,61,35,0.08);
  --radius-sm: 6px;
  --radius-md: 10px;
  --radius-lg: 14px;
  --radius-xl: 20px;
  --transition: all 0.25s ease;
}

/* Top Bar */
.uaa-topbar {
  background: var(--green-dark);
  color: var(--green-muted);
  font-size: 13px;
  padding: 8px 0;
}
.uaa-topbar .uaa-container {
  display: flex;
  justify-content: space-between;
  align-items: center;
}
.uaa-topbar a {
  color: var(--green-muted);
  transition: var(--transition);
}
.uaa-topbar a:hover {
  color: var(--white);
}

/* Header */
.uaa-header {
  border-bottom: 1px solid var(--line);
  padding: 16px 0;
  background: var(--white);
  position: sticky;
  top: 0;
  z-index: 1000;
}
.uaa-header.scrolled {
  box-shadow: 0 2px 20px rgba(0,61,35,0.08);
}
.uaa-header .uaa-container {
  display: flex;
  align-items: center;
  justify-content: space-between;
}
.uaa-logo {
  display: flex;
  align-items: center;
  gap: 10px;
}
.uaa-logo-mark {
  width: 42px;
  height: 42px;
  border-radius: var(--radius-sm);
  background: linear-gradient(135deg, var(--green-bright), var(--green-primary));
  display: flex;
  align-items: center;
  justify-content: center;
  color: var(--white);
  font-weight: 700;
  font-family: 'Poppins', sans-serif;
  font-size: 18px;
}
.uaa-logo-text {
  font-family: 'Poppins', sans-serif;
  font-weight: 700;
  font-size: 17px;
  color: var(--green-dark);
  line-height: 1.15;
}
.uaa-logo-text small {
  display: block;
  font-family: 'Source Sans 3', sans-serif;
  font-size: 11px;
  color: var(--muted);
  font-weight: 500;
  letter-spacing: 0.03em;
}
.uaa-nav ul {
  display: flex;
  gap: 28px;
  font-size: 14px;
  font-weight: 500;
  list-style: none;
  margin: 0;
  padding: 0;
}
.uaa-nav a {
  color: var(--ink);
  position: relative;
  transition: var(--transition);
}
.uaa-nav a:hover {
  color: var(--green-primary);
}
.uaa-nav a::after {
  content: '';
  position: absolute;
  bottom: -4px;
  left: 0;
  width: 0;
  height: 2px;
  background: var(--green-primary);
  transition: width 0.25s ease;
}
.uaa-nav a:hover::after {
  width: 100%;
}
.uaa-header-cta {
  display: flex;
  gap: 12px;
  align-items: center;
}
.uaa-menu-toggle {
  display: none;
  background: none;
  border: none;
  cursor: pointer;
  padding: 8px;
}
.uaa-menu-toggle span {
  display: block;
  width: 24px;
  height: 2px;
  background: var(--ink);
  margin: 5px 0;
  transition: var(--transition);
}

/* Hero */
.uaa-hero {
  background: linear-gradient(120deg, rgba(0,61,35,0.92) 0%, rgba(0,107,63,0.85) 100%);
  color: var(--white);
  padding: 100px 0 0;
  position: relative;
  overflow: hidden;
}
.uaa-hero::before {
  content: '';
  position: absolute;
  top: -50%;
  right: -20%;
  width: 600px;
  height: 600px;
  border-radius: 50%;
  background: rgba(0,168,89,0.08);
}
.uaa-hero-content {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 40px;
  align-items: center;
  margin-bottom: 80px;
}
.uaa-hero-text {
  max-width: 680px;
  position: relative;
  z-index: 2;
}
.uaa-hero-image {
  position: relative;
  z-index: 2;
}
.uaa-hero-image img {
  width: 100%;
  height: 380px;
  object-fit: cover;
  border-radius: var(--radius-lg);
  box-shadow: 0 20px 50px rgba(0,0,0,0.25);
}
.uaa-hero h1 {
  color: var(--white);
  margin-bottom: 16px;
}
.uaa-hero p {
  color: #C8E8D6;
  font-size: 16.5px;
  max-width: 540px;
}
.uaa-hero-badge {
  display: inline-flex;
  align-items: center;
  gap: 8px;
  background: rgba(0,168,89,0.2);
  border: 1px solid rgba(0,168,89,0.3);
  padding: 8px 16px;
  border-radius: 30px;
  font-size: 13px;
  color: #A8E6C3;
  margin-bottom: 20px;
  font-weight: 500;
}
.uaa-hero-badge::before {
  content: '✓';
  background: var(--green-bright);
  color: var(--white);
  width: 20px;
  height: 20px;
  border-radius: 50%;
  display: flex;
  align-items: center;
  justify-content: center;
  font-size: 11px;
  font-weight: 700;
}

/* Search Panel */
.uaa-search-wrap {
  position: relative;
  z-index: 2;
}
.uaa-search-tabs {
  display: flex;
  gap: 4px;
  position: absolute;
  top: -40px;
  left: 0;
}
.uaa-search-tabs span {
  background: rgba(255,255,255,0.12);
  color: var(--white);
  font-size: 13px;
  font-weight: 600;
  padding: 10px 18px;
  border-radius: 8px 8px 0 0;
  cursor: default;
}
.uaa-search-tabs span.active {
  background: var(--white);
  color: var(--green-dark);
}
.uaa-search-panel {
  background: var(--white);
  border-radius: var(--radius-lg);
  padding: 22px;
  display: grid;
  grid-template-columns: 1fr 1fr 1fr 1fr auto;
  gap: 14px;
  box-shadow: 0 30px 60px -25px rgba(0,61,35,0.4);
  align-items: end;
}
.uaa-field label {
  display: block;
  font-size: 12px;
  color: var(--muted);
  margin-bottom: 6px;
  font-weight: 600;
}
.uaa-field select,
.uaa-field input {
  width: 100%;
  border: 1px solid var(--line);
  border-radius: var(--radius-sm);
  padding: 11px 12px;
  font-size: 14px;
  color: var(--ink);
  background: var(--white);
  transition: var(--transition);
}
.uaa-field select:focus,
.uaa-field input:focus {
  outline: none;
  border-color: var(--green-primary);
  box-shadow: 0 0 0 3px rgba(0,107,63,0.1);
}
.uaa-search-panel .uaa-btn {
  padding: 12px 26px;
}
.uaa-hero-spacer {
  height: 50px;
}

/* Buttons */
.uaa-btn {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  gap: 8px;
  background: var(--green-primary);
  color: var(--white);
  padding: 14px 28px;
  border-radius: var(--radius-sm);
  font-weight: 600;
  font-size: 14px;
  border: none;
  cursor: pointer;
  transition: var(--transition);
  white-space: nowrap;
  text-decoration: none;
}
.uaa-btn:hover {
  background: var(--green-dark);
  transform: translateY(-1px);
  box-shadow: var(--shadow-md);
}
.uaa-btn-gold {
  background: var(--gold);
  color: var(--green-dark);
}
.uaa-btn-gold:hover {
  background: #C49A38;
}
.uaa-btn-outline {
  background: transparent;
  border: 1.5px solid var(--white);
  color: var(--white);
}
.uaa-btn-outline:hover {
  background: rgba(255,255,255,0.15);
}
.uaa-btn-outline-green {
  background: transparent;
  border: 1.5px solid var(--green-primary);
  color: var(--green-primary);
}
.uaa-btn-outline-green:hover {
  background: var(--green-primary);
  color: var(--white);
}
.uaa-btn-sm {
  padding: 10px 20px;
  font-size: 13px;
}

/* Sections */
.uaa-section {
  padding: 90px 0;
}
.uaa-section-head {
  max-width: 640px;
  margin-bottom: 48px;
}
.uaa-section-head.center {
  text-align: center;
  margin: 0 auto 48px;
}
.uaa-section-head p {
  color: var(--muted);
  margin-top: 10px;
  font-size: 15px;
}
.uaa-eyebrow {
  color: var(--green-bright);
  font-weight: 600;
  letter-spacing: 0.1em;
  text-transform: uppercase;
  font-size: 12px;
  display: block;
  margin-bottom: 8px;
  font-family: 'Poppins', sans-serif;
}

/* Filter Pills */
.uaa-filter-pills {
  display: flex;
  gap: 10px;
  margin-bottom: 36px;
  flex-wrap: wrap;
}
.uaa-filter-pills span {
  border: 1px solid var(--line);
  border-radius: 20px;
  padding: 8px 18px;
  font-size: 13.5px;
  font-weight: 500;
  color: var(--muted);
  cursor: pointer;
  transition: var(--transition);
}
.uaa-filter-pills span:hover {
  border-color: var(--green-primary);
  color: var(--green-primary);
}
.uaa-filter-pills span.active {
  background: var(--green-primary);
  color: var(--white);
  border-color: var(--green-primary);
}

/* Listings Grid */
.uaa-listings-grid {
  display: grid;
  grid-template-columns: repeat(3, 1fr);
  gap: 26px;
}
.uaa-listing-card {
  border: 1px solid var(--line);
  border-radius: var(--radius-lg);
  overflow: hidden;
  transition: var(--transition);
  background: var(--white);
  text-decoration: none;
  color: inherit;
}
.uaa-listing-card:hover {
  box-shadow: var(--shadow-lg);
  transform: translateY(-4px);
}
.uaa-listing-photo {
  height: 210px;
  background-size: cover;
  background-position: center;
  position: relative;
}
.uaa-listing-tag {
  position: absolute;
  top: 14px;
  left: 14px;
  background: var(--green-primary);
  color: var(--white);
  font-size: 11px;
  font-weight: 700;
  padding: 5px 12px;
  border-radius: 5px;
  text-transform: uppercase;
  letter-spacing: 0.03em;
}
.uaa-listing-tag.rent {
  background: var(--gold);
  color: var(--green-dark);
}
.uaa-agency-badge {
  position: absolute;
  top: 14px;
  right: 14px;
  background: var(--white);
  color: var(--green-primary);
  font-size: 11px;
  font-weight: 700;
  padding: 5px 10px;
  border-radius: 5px;
  display: flex;
  align-items: center;
  gap: 4px;
  box-shadow: var(--shadow-sm);
}
.uaa-listing-info {
  padding: 20px;
}
.uaa-listing-price {
  font-family: 'Poppins', serif;
  font-size: 20px;
  color: var(--green-primary);
  margin-bottom: 4px;
}
.uaa-listing-price small {
  color: var(--muted);
  font-size: 12px;
  font-family: 'Source Sans 3', sans-serif;
}
.uaa-listing-info h4 {
  font-size: 16px;
  margin-bottom: 4px;
  font-family: 'Source Sans 3', sans-serif;
  color: var(--ink);
}
.uaa-listing-loc {
  font-size: 13px;
  color: var(--muted);
  margin-bottom: 14px;
}
.uaa-listing-meta {
  display: flex;
  gap: 16px;
  font-size: 12.5px;
  color: var(--muted);
  border-top: 1px solid var(--line);
  padding-top: 12px;
  margin-bottom: 14px;
}
.uaa-agent-row {
  display: flex;
  align-items: center;
  gap: 10px;
}
.uaa-agent-row img {
  width: 32px;
  height: 32px;
  border-radius: 50%;
  object-fit: cover;
}
.uaa-agent-row span {
  font-size: 13px;
  font-weight: 600;
  color: var(--ink);
}
.uaa-agent-row small {
  display: block;
  font-size: 11px;
  color: var(--green-bright);
  font-weight: 600;
}

/* Why Choose Us */
.uaa-why-grid {
  display: grid;
  grid-template-columns: repeat(3, 1fr);
  gap: 30px;
}
.uaa-why-card {
  padding: 8px 0;
}
.uaa-why-icon {
  width: 56px;
  height: 56px;
  border-radius: var(--radius-md);
  background: var(--green-tint);
  color: var(--green-primary);
  display: flex;
  align-items: center;
  justify-content: center;
  font-size: 22px;
  margin-bottom: 18px;
}
.uaa-why-card h4 {
  font-size: 17px;
  margin-bottom: 10px;
  font-family: 'Source Sans 3', sans-serif;
  color: var(--ink);
}
.uaa-why-card p {
  color: var(--muted);
  font-size: 14.5px;
  margin-bottom: 12px;
}

/* About */
.uaa-about-grid {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 60px;
  align-items: center;
}
.uaa-quote-box {
  border-left: 3px solid var(--green-primary);
  padding-left: 20px;
  margin: 20px 0;
  color: var(--green-dark);
  font-family: 'Poppins', serif;
  font-size: 16px;
  font-style: italic;
}
.uaa-quote-by {
  font-size: 13.5px;
  color: var(--muted);
  margin-top: 8px;
  font-style: normal;
  font-weight: 600;
}

/* Stats */
.uaa-stats {
  background: var(--green-dark);
  color: var(--white);
  padding: 60px 0;
}
.uaa-stats-grid {
  display: grid;
  grid-template-columns: repeat(4, 1fr);
  text-align: center;
}
.uaa-stats-grid h3 {
  color: var(--white);
  font-size: 40px;
  margin-bottom: 4px;
}
.uaa-stats-grid p {
  color: #7FBF9A;
  font-size: 12.5px;
  text-transform: uppercase;
  letter-spacing: 0.04em;
}

/* Services Split */
.uaa-services-split {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 50px;
  align-items: center;
}
.uaa-check-list {
  list-style: none;
  padding: 0;
  margin: 0;
}
.uaa-check-list li {
  display: flex;
  gap: 12px;
  padding: 14px 0;
  border-bottom: 1px solid var(--line);
  font-size: 14.5px;
  color: var(--ink);
}
.uaa-check-list li::before {
  content: "✓";
  color: var(--green-bright);
  font-weight: 700;
  flex: 0 0 20px;
}

/* Contact */
.uaa-contact-grid {
  display: grid;
  grid-template-columns: 1.1fr 1fr;
  gap: 50px;
}
.uaa-form-row {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 16px;
  margin-bottom: 16px;
}
.uaa-form-field {
  margin-bottom: 16px;
}
.uaa-form-field label {
  display: block;
  font-size: 13px;
  font-weight: 600;
  margin-bottom: 6px;
  color: var(--ink);
}
.uaa-form-field input,
.uaa-form-field select,
.uaa-form-field textarea {
  width: 100%;
  border: 1px solid var(--line);
  border-radius: var(--radius-sm);
  padding: 12px;
  font-size: 14px;
  transition: var(--transition);
}
.uaa-form-field input:focus,
.uaa-form-field select:focus,
.uaa-form-field textarea:focus {
  outline: none;
  border-color: var(--green-primary);
  box-shadow: 0 0 0 3px rgba(0,107,63,0.1);
}
.uaa-form-field textarea {
  resize: vertical;
  min-height: 100px;
}
.uaa-full-row {
  margin-bottom: 16px;
}

/* CTA Band */
.uaa-cta-band {
  background: linear-gradient(120deg, var(--green-primary), var(--green-dark));
  color: var(--white);
  padding: 70px 0;
  text-align: center;
}
.uaa-cta-band h2 {
  color: var(--white);
  font-size: 28px;
  margin-bottom: 12px;
}
.uaa-cta-band p {
  color: #A8E6C3;
  max-width: 560px;
  margin: 0 auto 26px;
}
.uaa-cta-buttons {
  display: flex;
  gap: 14px;
  justify-content: center;
}

/* Footer */
.uaa-footer {
  background: var(--green-dark);
  color: #7FBF9A;
  padding: 60px 0 26px;
}
.uaa-footer-grid {
  display: grid;
  grid-template-columns: 2fr 1fr 1fr 1.3fr;
  gap: 40px;
  margin-bottom: 44px;
}
.uaa-footer-grid h5 {
  color: var(--white);
  font-size: 13.5px;
  margin-bottom: 16px;
  text-transform: uppercase;
  letter-spacing: 0.03em;
  font-family: 'Source Sans 3', sans-serif;
}
.uaa-footer-grid ul {
  list-style: none;
  padding: 0;
  margin: 0;
}
.uaa-footer-grid li {
  margin-bottom: 9px;
  font-size: 13.5px;
}
.uaa-footer-grid a:hover {
  color: var(--white);
}
.uaa-footer-bottom {
  border-top: 1px solid #0A3A1E;
  padding-top: 22px;
  display: flex;
  justify-content: space-between;
  font-size: 12.5px;
  color: #4A8A65;
}

/* Scroll Animations */
.uaa-animate-on-scroll {
  opacity: 0;
  transform: translateY(30px);
  transition: opacity 0.7s ease-out, transform 0.7s ease-out;
}
.uaa-animate-on-scroll.is-visible {
  opacity: 1;
  transform: translateY(0);
}
.uaa-animate-on-scroll .uaa-why-card,
.uaa-animate-on-scroll .uaa-listing-card,
.uaa-animate-on-scroll .uaa-stats-grid > div {
  opacity: 0;
  transform: translateY(20px);
  transition: opacity 0.5s ease-out, transform 0.5s ease-out;
}
.uaa-animate-on-scroll.is-visible .uaa-why-card,
.uaa-animate-on-scroll.is-visible .uaa-listing-card,
.uaa-animate-on-scroll.is-visible .uaa-stats-grid > div {
  opacity: 1;
  transform: translateY(0);
}
.uaa-animate-on-scroll.is-visible .uaa-why-card:nth-child(1),
.uaa-animate-on-scroll.is-visible .uaa-listing-card:nth-child(1),
.uaa-animate-on-scroll.is-visible .uaa-stats-grid > div:nth-child(1) {
  transition-delay: 0.1s;
}
.uaa-animate-on-scroll.is-visible .uaa-why-card:nth-child(2),
.uaa-animate-on-scroll.is-visible .uaa-listing-card:nth-child(2),
.uaa-animate-on-scroll.is-visible .uaa-stats-grid > div:nth-child(2) {
  transition-delay: 0.2s;
}
.uaa-animate-on-scroll.is-visible .uaa-why-card:nth-child(3),
.uaa-animate-on-scroll.is-visible .uaa-listing-card:nth-child(3),
.uaa-animate-on-scroll.is-visible .uaa-stats-grid > div:nth-child(3) {
  transition-delay: 0.3s;
}
.uaa-animate-on-scroll.is-visible .uaa-stats-grid > div:nth-child(4) {
  transition-delay: 0.4s;
}

/* Responsive */
@media (max-width: 980px) {
  .uaa-nav { display: none; }
  .uaa-header-cta { display: none; }
  .uaa-menu-toggle { display: block; }
  .uaa-hero-content { grid-template-columns: 1fr; margin-bottom: 60px; }
  .uaa-hero-image { display: none; }
  .uaa-search-panel { grid-template-columns: 1fr; }
  .uaa-listings-grid, .uaa-why-grid, .uaa-about-grid, .uaa-services-split, .uaa-contact-grid { grid-template-columns: 1fr; }
  .uaa-stats-grid { grid-template-columns: repeat(2, 1fr); gap: 30px; }
  .uaa-footer-grid { grid-template-columns: 1fr 1fr; }
}
@media (max-width: 600px) {
  .uaa-hero { padding: 60px 0 0; }
  .uaa-hero h1 { font-size: 24px; }
  .uaa-search-tabs { display: none; }
  .uaa-hero-spacer { height: 30px; }
  .uaa-section { padding: 50px 0; }
  .uaa-listings-grid { grid-template-columns: 1fr; }
  .uaa-stats-grid { grid-template-columns: 1fr 1fr; gap: 20px; }
  .uaa-stats-grid h3 { font-size: 28px; }
  .uaa-form-row { grid-template-columns: 1fr; }
  .uaa-cta-buttons { flex-direction: column; align-items: center; }
  .uaa-footer-grid { grid-template-columns: 1fr; }
  .uaa-footer-bottom { flex-direction: column; gap: 8px; text-align: center; }
}
